section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/enterprise-xr-applications.json",
  "title": "Enterprise XR Applications",
  "type": "object",
  "required": [
    "artefact_id",
    "project_id",
    "platform",
    "session_comfort_budget_min",
    "integrations",
    "security_review_ref",
    "a11y_compliance",
    "roi_metrics",
    "owners",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "project_id": {
      "type": "string",
      "description": "project_id",
      "minLength": 1
    },
    "platform": {
      "type": "string",
      "description": "platform",
      "minLength": 1
    },
    "session_comfort_budget_min": {
      "type": "number",
      "description": "session_comfort_budget_min (numeric)"
    },
    "integrations": {
      "type": "string",
      "description": "integrations",
      "minLength": 1
    },
    "security_review_ref": {
      "type": "string",
      "description": "security_review_ref",
      "minLength": 1
    },
    "a11y_compliance": {
      "type": "string",
      "description": "a11y_compliance",
      "minLength": 1
    },
    "roi_metrics": {
      "type": "array",
      "description": "roi_metrics (array)",
      "minItems": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
